public OpenMapRealVector ebeDivide(RealVector v) {
    checkVectorDimensions(v.getDimension());
    OpenMapRealVector res = new OpenMapRealVector(this);
    Iterator iter = res.entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        double val = v.getEntry(iter.key());
        if (val != 0.0) {
            res.setEntry(iter.key(), iter.value() / val);
        } else {
            res.setEntry(iter.key(), Double.NaN);
        }
    }
    return res;
}

public OpenMapRealVector ebeDivide(double[] v) {
    checkVectorDimensions(v.length);
    OpenMapRealVector res = new OpenMapRealVector(this);
    Iterator iter = res.entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        double val = v[iter.key()];
        if (val != 0.0) {
            res.setEntry(iter.key(), iter.value() / val);
        } else {
            res.setEntry(iter.key(), Double.NaN);
        }
    }
    return res;
}

public OpenMapRealVector ebeMultiply(RealVector v) {
    checkVectorDimensions(v.getDimension());
    OpenMapRealVector res = new OpenMapRealVector(this);
    Iterator iter = res.entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        double product = iter.value() * v.getEntry(iter.key());
        if (product != 0.0) {
            res.setEntry(iter.key(), product);
        } else {
            iter.remove();
        }
    }
    return res;
}

public OpenMapRealVector ebeMultiply(double[] v) {
    checkVectorDimensions(v.length);
    OpenMapRealVector res = new OpenMapRealVector(this);
    Iterator iter = res.entries.iterator();
    while (iter.hasNext()) {
        iter.advance();
        double product = iter.value() * v[iter.key()];
        if (product != 0.0) {
            res.setEntry(iter.key(), product);
        } else {
            iter.remove();
        }
    }
    return res;
}
